125	int calculate_estimated_query_cost(int N_val, int k_pivots_val) {
126	    if (k_pivots_val <= 0) return 0;
127	    if (k_pivots_val == 1) {
128	        return (N_val > 1) ? (N_val - 1) : 0;
129	    }
130	
131	    double cost = 0;
132	    cost += static_cast<double>(k_pivots_val) * estimate_log2(static_cast<double>(k_pivots_val));
133	    for (int j = 2; j < k_pivots_val; ++j) {
134	        if (j-1 > 0) cost += estimate_log2(static_cast<double>(j - 1));
135	    }
136	    cost += static_cast<double>(N_val - k_pivots_val) * estimate_log2(static_cast<double>(k_pivots_val));
137	    return static_cast<int>(std::ceil(cost));
138	}
