375	    // Exhaust remaining queries
376	    int dummy_item_0_idx = 0;
377	    int dummy_item_1_idx = 1;
378	    while(queries_made < Q_total_global) {
379	        perform_query_actual({dummy_item_0_idx}, {dummy_item_1_idx});
380	        dummy_item_1_idx = (dummy_item_1_idx + 1) % N_items_global;
381	        if (dummy_item_1_idx == dummy_item_0_idx) {
382	            dummy_item_1_idx = (dummy_item_1_idx + 1) % N_items_global;
383	        }
384	    }
385	
386	    // --- Assignment Phase: Guided SA with directed moves ---
387	
388	    // Sort items by estimated weight (descending) for initial assignment
389	    std::vector<int> items_sorted_desc(N_items_global);
390	    std::iota(items_sorted_desc.begin(), items_sorted_desc.end(), 0);
391	    std::sort(items_sorted_desc.begin(), items_sorted_desc.end(), [&](int a, int b) {
392	        return estimated_weights[a] > estimated_weights[b];
393	    });
394	
395	    // Also create a sorted-by-weight index for quick lookup
396	    std::vector<int> weight_rank(N_items_global); // rank 0 = heaviest
397	    for (int i = 0; i < N_items_global; i++) {
398	        weight_rank[items_sorted_desc[i]] = i;
399	    }
400	
401	    std::vector<int> assignment_array(N_items_global);
402	    std::vector<long long> group_sums_array(D_groups_global, 0);
403	    long long total_sum_est_val = 0;
404	    std::vector<std::vector<int>> group_items_indices(D_groups_global);
405	
406	    // Initial assignment: Snake/zigzag draft (better than greedy for balanced partition)
407	    {
408	        int group_idx = 0;
409	        int direction = 1; // 1 = forward, -1 = backward
410	        for (int i = 0; i < N_items_global; i++) {
411	            int item_actual_idx = items_sorted_desc[i];
412	            assignment_array[item_actual_idx] = group_idx;
413	            group_sums_array[group_idx] += estimated_weights[item_actual_idx];
414	            group_items_indices[group_idx].push_back(item_actual_idx);
415	
416	            group_idx += direction;
417	            if (group_idx >= D_groups_global) {
418	                group_idx = D_groups_global - 1;
419	                direction = -1;
420	            } else if (group_idx < 0) {
421	                group_idx = 0;
422	                direction = 1;
423	            }
424	        }
425	    }
426	
427	    for (int i = 0; i < N_items_global; i++) {
428	        total_sum_est_val += estimated_weights[i];
429	    }
430	
431	    // Also compute greedy LPT solution and keep the better one
432	    std::vector<int> greedy_assignment(N_items_global);
433	    std::vector<long long> greedy_group_sums(D_groups_global, 0);
434	    std::vector<std::vector<int>> greedy_group_items(D_groups_global);
435	
436	    for (int i = 0; i < N_items_global; i++) {
437	        int item_actual_idx = items_sorted_desc[i];
438	        int best_grp = 0;
439	        long long min_sum = greedy_group_sums[0];
440	        for (int j = 1; j < D_groups_global; j++) {
441	            if (greedy_group_sums[j] < min_sum) {
442	                min_sum = greedy_group_sums[j];
443	                best_grp = j;
444	            }
445	        }
446	        greedy_assignment[item_actual_idx] = best_grp;
447	        greedy_group_sums[best_grp] += estimated_weights[item_actual_idx];
448	        greedy_group_items[best_grp].push_back(item_actual_idx);
449	    }
450	
451	    // Compare snake vs greedy, use the better one
452	    double snake_sum_sq = 0, greedy_sum_sq = 0;
