char perform_query_actual(const std::vector<int>& L_items, const std::vector<int>& R_items) {
    queries_made++;
    std::cout << L_items.size() << " " << R_items.size();
    for (int item_idx : L_items) {
        std::cout << " " << item_idx;
    }
