        } else {
            arr[k++] = R[j++];
        }
    }
    while (i < n1) arr[k++] = L[i++];
    while (j < n2) arr[k++] = R[j++];
}

int estimate_sort_cost(int k) {
    if (k <= 1) return 0;
    return (int)std::ceil(k * std::log2((double)k));
}

int estimate_place_cost(int n_items, int k_sorted) {
    if (k_sorted <= 0) return 0;
    return (int)std::ceil(n_items * std::log2((double)(k_sorted + 1)));
}

double calculate_variance_from_sums(double sum_sq, double total, int d) {
    if (d <= 0) return 1e18;
    double mean = total / d;
    double var = sum_sq / d - mean * mean;
    return std::max(0.0, var);
}

