    std::vector<int> sorted_all(N);
    std::vector<int> item_rank(N, -1); // rank 0 = lightest

    if (k_sort == N) {
        sorted_all = sort_items;
    } else {
        // Mark which items are already sorted
        std::vector<bool> is_sorted(N, false);
        for (int idx : sort_items) is_sorted[idx] = true;

        // Place each unsorted item among sorted items via binary search
        std::vector<int> placement_order;
        for (int i = 0; i < N; i++) {
            if (!is_sorted[i]) placement_order.push_back(i);
        }

