    // E[X_{(k:N)}] = (1/λ) * sum_{j=0}^{k-1} 1/(N-j)  where λ = 10^-5, 1/λ = 100000
    // k is 1-indexed rank, so for 0-indexed rank r: E = 100000 * sum_{j=0}^{r} 1/(N-j)
    const double INV_LAMBDA = 100000.0;
