    double cumsum = 0.0;
    for (int r = 0; r < N; r++) {
        cumsum += 1.0 / (N - r);
        expected_order_stat[r] = INV_LAMBDA * cumsum;
    }

    // Compute prefix sums of expected order statistics (for ratio refinement)
    std::vector<double> prefix_sum_expected(N + 1, 0.0);
    for (int r = 0; r < N; r++) {
        prefix_sum_expected[r + 1] = prefix_sum_expected[r] + expected_order_stat[r];
    }

