    int num_to_refine = 0;
    if (queries_per_item > 0) {
        num_to_refine = std::min(remaining_queries / queries_per_item, N / 2);
        num_to_refine = std::min(num_to_refine, 30); // cap to avoid diminishing returns
    }

    // For each refined item, store the calibrated weight
