# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <cmath>
#include <chrono>
#include <random>
#include <climits>
#include <map>

std::chrono::steady_clock::time_point program_start_time;
std::chrono::milliseconds time_limit_ms(1850);

int N, D, Q;
int queries_made = 0;
std::mt19937 rng_engine;

std::map<std::pair<int,int>, char> cmp_cache;

char perform_query(const std::vector<int>& L, const std::vector<int>& R) {
    queries_made++;
    std::cout << L.size() << " " << R.size();
    for (int x : L) std::cout << " " << x;
    for (int x : R) std::cout << " " << x;
    std::cout << std::endl;
    char c;
    std::cin >> c;
    return c;
}

char compare_items(int a, int b) {
    if (a == b) return '=';
    auto key = std::make_pair(std::min(a, b), std::max(a, b));
    auto it = cmp_cache.find(key);
    if (it != cmp_cache.end()) {
        char c = it->second;
        return (a == key.first) ? c : (c == '<' ? '>' : (c == '>' ? '<' : '='));
    }
    if (queries_made >= Q) return '=';
    char c = perform_query({a}, {b});
    if (a == key.first) {
        cmp_cache[key] = c;
    } else {
        cmp_cache[key] = (c == '<' ? '>' : (c == '>' ? '<' : '='));
    }
    return c;
}

void merge_sort(std::vector<int>& arr, int left, int right) {
    if (left >= right) return;
    int mid = left + (right - left) / 2;
    merge_sort(arr, left, mid);
    merge_sort(arr, mid + 1, right);

    int n1 = mid - left + 1;
    int n2 = right - mid;
    std::vector<int> L(n1), R(n2);
    for (int i = 0; i < n1; i++) L[i] = arr[left + i];
    for (int j = 0; j < n2; j++) R[j] = arr[mid + 1 + j];

    int i = 0, j = 0, k = left;
    while (i < n1 && j < n2) {
        char cmp = compare_items(L[i], R[j]);
        if (cmp == '<' || cmp == '=') {
            arr[k++] = L[i++];
        } else {
            arr[k++] = R[j++];
        }
    }
    while (i < n1) arr[k++] = L[i++];
    while (j < n2) arr[k++] = R[j++];
}

double calculate_variance_from_sums(double sum_sq, double total, int d) {
    if (d <= 0) return 1e18;
    double mean = total / d;
    double var = sum_sq / d - mean * mean;
    return std::max(0.0, var);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    program_start_time = std::chrono::steady_clock::now();
    rng_engine.seed(std::chrono::duration_cast<std::chrono::nanoseconds>(
        std::chrono::steady_clock::now().time_since_epoch()).count());

    std::cin >> N >> D >> Q;

    // === WEIGHT ESTIMATION PHASE ===
    // Strategy: Sort all N items using merge sort, then estimate weights using
    // exponential distribution order statistics + refinement via multi-item queries.

    // Step 1: Determine budget allocation
    // Merge sort N items costs ~N*log2(N) comparisons
    // Remaining budget used for weight refinement via group comparisons
    int sort_budget = (int)std::ceil(N * std::log2((double)N)) + N; // generous estimate

    // We always sort all N items - it's the most fundamental info we can get
    std::vector<int> sorted_items(N);
    std::iota(sorted_items.begin(), sorted_items.end(), 0);
    merge_sort(sorted_items, 0, N - 1);

    // sorted_items[0] is lightest, sorted_items[N-1] is heaviest

    // Step 2: Detect equality groups from comparison cache
    std::vector<int> eq_group(N, -1); // eq_group[rank] = leader rank
    for (int r = 0; r < N; r++) eq_group[r] = r;
    for (int r = 0; r < N - 1; r++) {
        int a = sorted_items[r], b = sorted_items[r + 1];
        auto key = std::make_pair(std::min(a, b), std::max(a, b));
        auto it = cmp_cache.find(key);
        if (it != cmp_cache.end() && it->second == '=') {
            eq_group[r + 1] = eq_group[r];
        }
    }

    // Step 3: Use remaining queries for magnitude estimation
    // Compare item_r vs {item_0, item_1, ..., item_{m-1}} to find breakpoint
    // This tells us: w_r is between sum(w_0..w_{m-1}) and sum(w_0..w_m)

    int remaining = Q - queries_made;

    // For each item from heaviest to lightest, try to find how it compares to prefix sums
    // Store breakpoint info: item at rank r > sum of items at ranks 0..break_r-1
    //                        item at rank r <= sum of items at ranks 0..break_r
    std::vector<int> break_lower(N, -1); // item > sum(0..break_lower-1)
    std::vector<int> break_upper(N, -1); // item <= sum(0..break_upper-1)

    // Prioritize heaviest items (they contribute most to variance if misestimated)
    // Binary search for each item costs log2(rank) queries
    for (int r = N - 1; r >= 1 && queries_made < Q; r--) {
        int item = sorted_items[r];
        int max_prefix = r; // can compare against at most r items (all lighter ones)

        // Binary search: find largest m such that item >= sum(lightest m items)
        int lo = 1, hi = max_prefix;
        int found_lower = 0; // item > sum of 0 items (trivially)
        bool found_upper = false;

        while (lo <= hi && queries_made < Q) {
            int mid = (lo + hi) / 2;
            std::vector<int> right_side;
            for (int i = 0; i < mid; i++) right_side.push_back(sorted_items[i]);

            char cmp = perform_query({item}, right_side);
            if (cmp == '>') {
                found_lower = mid;
                lo = mid + 1;
            } else if (cmp == '<') {
                if (!found_upper || mid < break_upper[r]) {
                    break_upper[r] = mid;
                }
                found_upper = true;
                hi = mid - 1;
            } else {
                // Equal: we know exact relationship
                found_lower = mid;
                break_upper[r] = mid;
                found_upper = true;
                break;
            }
        }
        break_lower[r] = found_lower;
        if (!found_upper) break_upper[r] = -1; // no upper bound found
    }

    // Step 4: Assign weights using order statistics + refinement constraints
    // Expected order statistics for Exp(lambda=10^-5):
    // E[X_{(r+1:N)}] = (1/lambda) * sum_{j=0}^{r} 1/(N-j)
    const double INV_LAMBDA = 100000.0;
    std::vector<double> expected_weight(N);
    double cumsum = 0.0;
    for (int r = 0; r < N; r++) {
        cumsum += 1.0 / (N - r);
        expected_weight[r] = INV_LAMBDA * cumsum;
    }

    // Build prefix sums of expected weights
    std::vector<double> prefix_expected(N + 1, 0.0);
    for (int r = 0; r < N; r++) {
        prefix_expected[r + 1] = prefix_expected[r] + expected_weight[r];
    }

    // Now use the breakpoint information to calibrate
    // If item at rank r > sum(items 0..m-1), then w_r > sum(w_0..w_{m-1})
    // We use this to rescale: if expected says w_r should be X and sum(0..m-1) should be S,
    // but the comparison shows w_r > S, then our scale is at least w_r/S > 1

    // Simple approach: for items with breakpoint info, estimate weight as midpoint
    // between prefix_sum(break_lower) and prefix_sum(break_upper)
    std::vector<double> final_weight(N);

    // Start with expected weights
    for (int r = 0; r < N; r++) {
        final_weight[r] = expected_weight[r];
    }

    // Apply calibration from breakpoint data
    // Key insight: we use the ACTUAL weights (iteratively refined) for prefix sums
    // Start from lightest (least uncertain), build up
    std::vector<double> actual_prefix(N + 1, 0.0);

    // First pass: assign expected weights
    for (int r = 0; r < N; r++) {
        actual_prefix[r + 1] = actual_prefix[r] + final_weight[r];
    }

    // Second pass: use breakpoints to refine heavy items
    for (int r = 1; r < N; r++) {
        if (break_lower[r] > 0 || break_upper[r] > 0) {
            double lower_bound = 0.0;
            double upper_bound = 1e18;

            if (break_lower[r] > 0) {
                // w_r > sum(w_0..w_{break_lower-1})
                lower_bound = actual_prefix[break_lower[r]];
            }
            if (break_upper[r] > 0) {
                // w_r <= sum(w_0..w_{break_upper-1})
                upper_bound = actual_prefix[break_upper[r]];
            }

            if (break_lower[r] > 0 && break_upper[r] > 0 && break_upper[r] == break_lower[r]) {
                // Exact: w_r = sum(w_0..w_{m-1})
                final_weight[r] = actual_prefix[break_lower[r]];
            } else if (lower_bound > 0 && upper_bound < 1e17) {
                // Estimate as geometric mean of bounds
                final_weight[r] = std::sqrt(lower_bound * upper_bound);
            } else if (lower_bound > 0) {
                // Only lower bound: use lower_bound * 1.3 (expected to be somewhat above)
                final_weight[r] = lower_bound * 1.3;
            } else if (upper_bound < 1e17) {
                // Only upper bound: use upper_bound * 0.7
                final_weight[r] = upper_bound * 0.7;
            }
            // Ensure monotonicity with previous item
            if (r > 0 && final_weight[r] < final_weight[r-1]) {
