            long long w1 = estimated_weights[best_h], w2 = estimated_weights[best_l];
            long long old1 = group_sums[heavy_g], old2 = group_sums[light_g];
            long long new1 = old1 - w1 + w2, new2 = old2 - w2 + w1;

