            double delta = new_var - current_var;

            if (delta < 0 || (T > 1e-15 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var;
                current_sum_sq = new_sq;
                group_sums[heavy_g] = new1;
                group_sums[light_g] = new2;
                assignment[best_h] = light_g;
                assignment[best_l] = heavy_g;

                int pos1 = item_pos[best_h];
                int back1 = group_items[heavy_g].back();
                if (best_h != back1) { group_items[heavy_g][pos1] = back1; item_pos[back1] = pos1; }
                group_items[heavy_g].pop_back();

                int pos2 = item_pos[best_l];
                int back2 = group_items[light_g].back();
                if (best_l != back2) { group_items[light_g][pos2] = back2; item_pos[back2] = pos2; }
                group_items[light_g].pop_back();

                group_items[light_g].push_back(best_h);
                item_pos[best_h] = group_items[light_g].size() - 1;
                group_items[heavy_g].push_back(best_l);
                item_pos[best_l] = group_items[heavy_g].size() - 1;

                if (new_var < best_var) { best_var = new_var; best_assignment = assignment; }
            }
        } else if (move < 8) {
            // Random relocate
            int item = item_dist(rng_engine);
            int old_g = assignment[item];
            int new_g = group_dist_r(rng_engine);
            if (new_g == old_g) continue;

            long long w = estimated_weights[item];
            long long old_a = group_sums[old_g], old_b = group_sums[new_g];
            long long new_a = old_a - w, new_b = old_b + w;

            double new_sq = current_sum_sq - (double)old_a*old_a - (double)old_b*old_b
                          + (double)new_a*new_a + (double)new_b*new_b;
            double new_var = calculate_variance_from_sums(new_sq, (double)total_sum, D);
            double delta = new_var - current_var;

            if (delta < 0 || (T > 1e-15 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var;
                current_sum_sq = new_sq;
                group_sums[old_g] = new_a;
                group_sums[new_g] = new_b;
                assignment[item] = new_g;

                int pos = item_pos[item];
                int last = group_items[old_g].back();
                if (item != last) { group_items[old_g][pos] = last; item_pos[last] = pos; }
                group_items[old_g].pop_back();
                group_items[new_g].push_back(item);
                item_pos[item] = group_items[new_g].size() - 1;

                if (new_var < best_var) { best_var = new_var; best_assignment = assignment; }
            }
        } else {
            // Random swap
            int g1 = group_dist_r(rng_engine), g2 = group_dist_r(rng_engine);
            if (g1 == g2 || group_items[g1].empty() || group_items[g2].empty()) continue;

            int item1 = group_items[g1][rng_engine() % group_items[g1].size()];
            int item2 = group_items[g2][rng_engine() % group_items[g2].size()];

            long long w1 = estimated_weights[item1], w2 = estimated_weights[item2];
            long long old1 = group_sums[g1], old2 = group_sums[g2];
            long long new1 = old1 - w1 + w2, new2 = old2 - w2 + w1;

            double new_sq = current_sum_sq - (double)old1*old1 - (double)old2*old2
                          + (double)new1*new1 + (double)new2*new2;
            double new_var = calculate_variance_from_sums(new_sq, (double)total_sum, D);
            double delta = new_var - current_var;

            if (delta < 0 || (T > 1e-15 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var;
                current_sum_sq = new_sq;
                group_sums[g1] = new1;
                group_sums[g2] = new2;
                assignment[item1] = g2;
                assignment[item2] = g1;

                int pos1 = item_pos[item1];
                int back1 = group_items[g1].back();
                if (item1 != back1) { group_items[g1][pos1] = back1; item_pos[back1] = pos1; }
                group_items[g1].pop_back();

                int pos2 = item_pos[item2];
                int back2 = group_items[g2].back();
                if (item2 != back2) { group_items[g2][pos2] = back2; item_pos[back2] = pos2; }
                group_items[g2].pop_back();

                group_items[g2].push_back(item1);
                item_pos[item1] = group_items[g2].size() - 1;
                group_items[g1].push_back(item2);
                item_pos[item2] = group_items[g1].size() - 1;

                if (new_var < best_var) { best_var = new_var; best_assignment = assignment; }
            }
        }
    }

    for (int i = 0; i < N; i++) {
        std::cout << best_assignment[i] << (i == N - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}
