int N, D, Q;
int queries_made = 0;
std::mt19937 rng_engine;

std::map<std::pair<int,int>, char> cmp_cache;

char perform_query(const std::vector<int>& L, const std::vector<int>& R) {
    queries_made++;
    std::cout << L.size() << " " << R.size();
    for (int x : L) std::cout << " " << x;
    for (int x : R) std::cout << " " << x;
    std::cout << std::endl;
    char c;
    std::cin >> c;
    return c;
}

char compare_items(int a, int b) {
    if (a == b) return '=';
    auto key = std::make_pair(std::min(a, b), std::max(a, b));
    auto it = cmp_cache.find(key);
    if (it != cmp_cache.end()) {
        char c = it->second;
        return (a == key.first) ? c : (c == '<' ? '>' : (c == '>' ? '<' : '='));
    }
    if (queries_made >= Q) return '=';
    char c = perform_query({a}, {b});
    if (a == key.first) {
        cmp_cache[key] = c;
    } else {
        cmp_cache[key] = (c == '<' ? '>' : (c == '>' ? '<' : '='));
    }
    return c;
}

void merge_sort(std::vector<int>& arr, int left, int right) {
    if (left >= right) return;
    int mid = left + (right - left) / 2;
    merge_sort(arr, left, mid);
    merge_sort(arr, mid + 1, right);

    int n1 = mid - left + 1;
    int n2 = right - mid;
    std::vector<int> L(n1), R(n2);
    for (int i = 0; i < n1; i++) L[i] = arr[left + i];
    for (int j = 0; j < n2; j++) R[j] = arr[mid + 1 + j];

    int i = 0, j = 0, k = left;
    while (i < n1 && j < n2) {
        char cmp = compare_items(L[i], R[j]);
        if (cmp == '<' || cmp == '=') {
            arr[k++] = L[i++];
        } else {
            arr[k++] = R[j++];
        }
    }
    while (i < n1) arr[k++] = L[i++];
    while (j < n2) arr[k++] = R[j++];
}

double log2_est(double val) {
    if (val <= 1.0) return 0.0;
    return std::log2(val);
}

int estimate_sort_cost(int k) {
    if (k <= 1) return 0;
    return (int)std::ceil(k * log2_est((double)k));
}

int estimate_place_cost(int n_remaining, int k_sorted) {
    if (k_sorted <= 0 || n_remaining <= 0) return 0;
    return (int)std::ceil(n_remaining * log2_est((double)(k_sorted + 1)));
}

double calculate_variance_from_sums(double sum_sq, double total, int d) {
    if (d <= 0) return 1e18;
    double mean = total / d;
    double var = sum_sq / d - mean * mean;
    return std::max(0.0, var);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    program_start_time = std::chrono::steady_clock::now();
    rng_engine.seed(std::chrono::duration_cast<std::chrono::nanoseconds>(
        std::chrono::steady_clock::now().time_since_epoch()).count());

    std::cin >> N >> D >> Q;

    // === WEIGHT ESTIMATION PHASE ===
    // Strategy: Sort as many items as possible, assign weights from exponential
    // distribution order statistics, use remaining queries for targeted refinement.

    // Step 1: Determine how many items we can sort + place
    int k_sort = 1;
    for (int k = N; k >= 1; k--) {
        int cost = estimate_sort_cost(k) + estimate_place_cost(N - k, k);
        if (cost <= Q) {
            k_sort = k;
            break;
        }
    }
    k_sort = std::min(k_sort, N);

    // Step 2: Select and sort pivot items
    std::vector<int> pivot_items(k_sort);
    if (k_sort == N) {
        std::iota(pivot_items.begin(), pivot_items.end(), 0);
    } else {
        std::vector<int> all(N);
        std::iota(all.begin(), all.end(), 0);
        std::shuffle(all.begin(), all.end(), rng_engine);
        for (int i = 0; i < k_sort; i++) pivot_items[i] = all[i];
    }

    merge_sort(pivot_items, 0, k_sort - 1);
    // pivot_items[0] = lightest pivot, pivot_items[k_sort-1] = heaviest pivot

    // Step 3: Place remaining items among sorted pivots via binary search
    std::vector<int> sorted_all;
    std::vector<bool> is_pivot(N, false);
    for (int idx : pivot_items) is_pivot[idx] = true;

    sorted_all = pivot_items;

    // Insert non-pivots
    for (int i = 0; i < N; i++) {
        if (is_pivot[i]) continue;
        int lo = 0, hi = (int)sorted_all.size() - 1;
        int insert_pos = (int)sorted_all.size();

        while (lo <= hi && queries_made < Q) {
            int mid = lo + (hi - lo) / 2;
            char cmp = compare_items(i, sorted_all[mid]);
            if (cmp == '<') {
                insert_pos = mid;
                hi = mid - 1;
            } else if (cmp == '>') {
                lo = mid + 1;
            } else {
                insert_pos = mid;
                break;
            }
        }
        if (queries_made >= Q && lo <= hi) {
            insert_pos = lo;
        }
        sorted_all.insert(sorted_all.begin() + insert_pos, i);
    }

    int total_sorted = (int)sorted_all.size(); // should be N

    // Step 4: Detect equality groups
    std::vector<int> eq_leader(total_sorted);
    std::iota(eq_leader.begin(), eq_leader.end(), 0);
    for (int r = 0; r < total_sorted - 1; r++) {
        int a = sorted_all[r], b = sorted_all[r + 1];
        auto key = std::make_pair(std::min(a, b), std::max(a, b));
        auto it = cmp_cache.find(key);
        if (it != cmp_cache.end() && it->second == '=') {
            eq_leader[r + 1] = eq_leader[r];
        }
    }
    // Propagate
    for (int r = 0; r < total_sorted; r++) {
        int lead = r;
        while (eq_leader[lead] != lead) lead = eq_leader[lead];
        eq_leader[r] = lead;
    }

    // Step 5: Assign weights using exponential order statistics
    // E[X_{(r+1:N)}] = (1/lambda) * sum_{j=0}^{r} 1/(N-j)
    // where r is 0-indexed rank (0 = lightest)
    const double INV_LAMBDA = 100000.0;
    std::vector<double> expected_os(total_sorted);
    double cumsum = 0.0;
    for (int r = 0; r < total_sorted; r++) {
        cumsum += 1.0 / (total_sorted - r);
        expected_os[r] = INV_LAMBDA * cumsum;
    }

    // Step 6: Use remaining queries for scale calibration
    // Compare heaviest item against groups of lighter items to find its actual magnitude
    // relative to others. This is the most impactful calibration since heavy items
    // contribute most to partition variance.
    int remaining = Q - queries_made;

    // We'll do targeted comparisons: for the heaviest few items, compare against
    // cumulative groups to find the actual "breakpoint" - how many lighter items
    // they outweigh. This lets us scale the distribution properly.

    // Calibration: find how the heaviest item compares to prefix sums
    // w_{N-1} vs sum(w_0..w_{m-1}): binary search for m
    double scale_factor = 1.0; // scale to apply to expected_os

    if (remaining >= 3 && total_sorted >= 4) {
        int heaviest_rank = total_sorted - 1;
        int heaviest_item = sorted_all[heaviest_rank];

        // Binary search: find largest m s.t. heaviest > sum of lightest m items
        int lo = 1, hi = std::min(heaviest_rank, (int)std::min((long long)remaining * 2, (long long)total_sorted - 1));
        int break_lower = 0;
        int break_upper = -1;

        while (lo <= hi && queries_made < Q) {
            int mid = (lo + hi) / 2;
            std::vector<int> right_side;
            for (int r = 0; r < mid && r < heaviest_rank; r++) {
                right_side.push_back(sorted_all[r]);
            }
            if (right_side.empty()) break;

            char cmp = perform_query({heaviest_item}, right_side);
            if (cmp == '>' || cmp == '=') {
                break_lower = mid;
                lo = mid + 1;
            } else {
                break_upper = mid;
                hi = mid - 1;
            }
        }

        // Now we know: w_{heaviest} is between sum(os[0..break_lower-1]) and sum(os[0..break_upper-1])
        // Expected weight of heaviest: expected_os[heaviest_rank]
        // Expected sum of lightest m: sum(expected_os[0..m-1])

        if (break_lower > 0) {
            double expected_prefix_lower = 0.0;
            for (int r = 0; r < break_lower; r++) expected_prefix_lower += expected_os[r];

            double expected_prefix_upper = 1e18;
            if (break_upper > 0) {
                expected_prefix_upper = 0.0;
                for (int r = 0; r < break_upper; r++) expected_prefix_upper += expected_os[r];
            }

            // The heaviest item's actual weight should be approximately equal to
            // the prefix sum at the breakpoint. Let's estimate:
            // actual_heaviest ≈ (prefix_lower + prefix_upper) / 2  (in expected units)
            // But we assigned expected_os[heaviest_rank] as its weight.
            // So scale_factor = actual / expected = prefix_midpoint / expected_os[heaviest_rank]

            double actual_estimate;
            if (break_upper > 0) {
                actual_estimate = (expected_prefix_lower + expected_prefix_upper) / 2.0;
            } else {
                actual_estimate = expected_prefix_lower * 1.5; // only lower bound
            }

            if (expected_os[heaviest_rank] > 0) {
                double new_scale = actual_estimate / expected_os[heaviest_rank];
                // Only apply if it makes a reasonable adjustment
                if (new_scale > 0.1 && new_scale < 10.0) {
                    scale_factor = new_scale;
                }
            }
        }

        // Do the same for a few more heavy items if budget allows
        remaining = Q - queries_made;
        if (remaining >= 3 && total_sorted >= 6) {
            int second_rank = total_sorted - 2;
            int second_item = sorted_all[second_rank];

            lo = 1; hi = std::min(second_rank, (int)std::min((long long)remaining * 2, (long long)second_rank));
            int bl2 = 0, bu2 = -1;

            while (lo <= hi && queries_made < Q) {
                int mid = (lo + hi) / 2;
                std::vector<int> right_side;
                for (int r = 0; r < mid && r < second_rank; r++) {
                    right_side.push_back(sorted_all[r]);
                }
                if (right_side.empty()) break;

                char cmp = perform_query({second_item}, right_side);
                if (cmp == '>' || cmp == '=') {
                    bl2 = mid;
                    lo = mid + 1;
                } else {
                    bu2 = mid;
                    hi = mid - 1;
                }
            }

            if (bl2 > 0 && expected_os[second_rank] > 0) {
                double prefix_l = 0.0;
                for (int r = 0; r < bl2; r++) prefix_l += expected_os[r];
                double prefix_u = 1e18;
                if (bu2 > 0) {
                    prefix_u = 0.0;
                    for (int r = 0; r < bu2; r++) prefix_u += expected_os[r];
                }

                double actual2;
                if (bu2 > 0) actual2 = (prefix_l + prefix_u) / 2.0;
                else actual2 = prefix_l * 1.5;

                double scale2 = actual2 / expected_os[second_rank];
                if (scale2 > 0.1 && scale2 < 10.0) {
                    // Average with first scale estimate
                    scale_factor = (scale_factor + scale2) / 2.0;
                }
            }
        }
    }

    // Step 7: Assign final weights
    std::vector<long long> estimated_weights(N);
    for (int r = 0; r < total_sorted; r++) {
        double w = expected_os[r] * scale_factor;
        estimated_weights[sorted_all[r]] = std::max(1LL, (long long)std::round(w));
    }

    // Apply equality constraints
    {
        int r = 0;
        while (r < total_sorted) {
            int start = r;
            while (r < total_sorted && eq_leader[r] == eq_leader[start]) r++;
            if (r - start > 1) {
                long long avg = 0;
                for (int i = start; i < r; i++) avg += estimated_weights[sorted_all[i]];
                avg /= (r - start);
                avg = std::max(1LL, avg);
                for (int i = start; i < r; i++) estimated_weights[sorted_all[i]] = avg;
            }
        }
    }

    // Ensure monotonicity
    for (int r = 1; r < total_sorted; r++) {
        if (estimated_weights[sorted_all[r]] < estimated_weights[sorted_all[r-1]]) {
            estimated_weights[sorted_all[r]] = estimated_weights[sorted_all[r-1]];
        }
    }

    // Exhaust remaining queries
    while (queries_made < Q) {
        perform_query({sorted_all[0]}, {sorted_all[std::min(1, total_sorted - 1)]});
    }

    // === PARTITIONING PHASE: Guided SA ===
    std::vector<int> items_sorted_desc(N);
    std::iota(items_sorted_desc.begin(), items_sorted_desc.end(), 0);
    std::sort(items_sorted_desc.begin(), items_sorted_desc.end(), [&](int a, int b) {
        return estimated_weights[a] > estimated_weights[b];
    });

    std::vector<int> assignment(N);
    std::vector<long long> group_sums(D, 0);
    std::vector<std::vector<int>> group_items(D);
    long long total_sum = 0;
    for (int i = 0; i < N; i++) total_sum += estimated_weights[i];

    // Snake draft
    {
        int g = 0, dir = 1;
        for (int i = 0; i < N; i++) {
            int item = items_sorted_desc[i];
            assignment[item] = g;
            group_sums[g] += estimated_weights[item];
            group_items[g].push_back(item);
            g += dir;
            if (g >= D) { g = D - 1; dir = -1; }
            else if (g < 0) { g = 0; dir = 1; }
        }
    }

    // Greedy LPT comparison
    std::vector<int> greedy_assign(N);
    std::vector<long long> greedy_sums(D, 0);
    std::vector<std::vector<int>> greedy_items(D);

    for (int i = 0; i < N; i++) {
        int item = items_sorted_desc[i];
        int best_g = 0;
        long long min_s = greedy_sums[0];
        for (int g = 1; g < D; g++) {
            if (greedy_sums[g] < min_s) { min_s = greedy_sums[g]; best_g = g; }
        }
        greedy_assign[item] = best_g;
        greedy_sums[best_g] += estimated_weights[item];
        greedy_items[best_g].push_back(item);
    }

    double snake_sq = 0, greedy_sq = 0;
    for (int g = 0; g < D; g++) {
        snake_sq += (double)group_sums[g] * group_sums[g];
        greedy_sq += (double)greedy_sums[g] * greedy_sums[g];
    }
    if (calculate_variance_from_sums(greedy_sq, (double)total_sum, D) <
        calculate_variance_from_sums(snake_sq, (double)total_sum, D)) {
        assignment = greedy_assign;
        group_sums = greedy_sums;
        group_items = greedy_items;
    }

    double current_sum_sq = 0;
    for (long long s : group_sums) current_sum_sq += (double)s * s;
    double current_var = calculate_variance_from_sums(current_sum_sq, (double)total_sum, D);

    std::vector<int> best_assignment = assignment;
    double best_var = current_var;

    double T_initial = std::max(1.0, current_var * 0.1);
    if (total_sum > 0 && current_var < 1e-9)
        T_initial = std::max(1.0, (double)total_sum / std::max(1, N) * 0.1);
    if (D <= 1) T_initial = 0;
    double T = T_initial, T_min = 1e-10;

    std::uniform_real_distribution<double> unif(0.0, 1.0);
    std::uniform_int_distribution<int> item_dist(0, N - 1);
    std::uniform_int_distribution<int> group_dist_r(0, D - 1);

    std::vector<int> item_pos(N);
    for (int g = 0; g < D; g++)
        for (int pos = 0; pos < (int)group_items[g].size(); pos++)
            item_pos[group_items[g][pos]] = pos;

    int iter = 0;
    const int CHECK_INTERVAL = 512;

    while (D > 1 && N > 0) {
        iter++;
        if (iter % CHECK_INTERVAL == 0) {
            auto now = std::chrono::steady_clock::now();
            if (std::chrono::duration_cast<std::chrono::milliseconds>(now - program_start_time) >= time_limit_ms) break;
            double elapsed = std::chrono::duration_cast<std::chrono::microseconds>(now - program_start_time).count() / 1000.0;
            double progress = elapsed / 1850.0;
            if (progress > 1.0) progress = 1.0;
            T = T_initial * std::pow(T_min / T_initial, progress);
        }
        if (T < 1e-15 && current_var < 1.0 + 1e-9) break;

        int move = rng_engine() % 10;

        if (move < 4) {
            int heavy_g = 0, light_g = 0;
            long long max_s = group_sums[0], min_s = group_sums[0];
            for (int g = 1; g < D; g++) {
                if (group_sums[g] > max_s) { max_s = group_sums[g]; heavy_g = g; }
                if (group_sums[g] < min_s) { min_s = group_sums[g]; light_g = g; }
            }
            if (heavy_g == light_g || group_items[heavy_g].empty()) continue;
            long long target = (max_s - min_s) / 2;
            int best_item = -1; long long best_diff = LLONG_MAX;
            for (int item : group_items[heavy_g]) {
                long long diff = std::abs(estimated_weights[item] - target);
                if (diff < best_diff) { best_diff = diff; best_item = item; }
            }
            if (best_item == -1) continue;
            long long w = estimated_weights[best_item];
            long long old_a = group_sums[heavy_g], old_b = group_sums[light_g];
            long long new_a = old_a - w, new_b = old_b + w;
            double new_sq = current_sum_sq - (double)old_a*old_a - (double)old_b*old_b + (double)new_a*new_a + (double)new_b*new_b;
            double new_var = calculate_variance_from_sums(new_sq, (double)total_sum, D);
            double delta = new_var - current_var;
            if (delta < 0 || (T > 1e-15 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var; current_sum_sq = new_sq;
                group_sums[heavy_g] = new_a; group_sums[light_g] = new_b;
                assignment[best_item] = light_g;
                int pos = item_pos[best_item];
                int last = group_items[heavy_g].back();
                if (best_item != last) { group_items[heavy_g][pos] = last; item_pos[last] = pos; }
                group_items[heavy_g].pop_back();
                group_items[light_g].push_back(best_item);
                item_pos[best_item] = group_items[light_g].size() - 1;
                if (new_var < best_var) { best_var = new_var; best_assignment = assignment; }
            }
        } else if (move < 6) {
            int heavy_g = 0, light_g = 0;
            long long max_s = group_sums[0], min_s = group_sums[0];
            for (int g = 1; g < D; g++) {
                if (group_sums[g] > max_s) { max_s = group_sums[g]; heavy_g = g; }
                if (group_sums[g] < min_s) { min_s = group_sums[g]; light_g = g; }
            }
            if (heavy_g == light_g || group_items[heavy_g].empty() || group_items[light_g].empty()) continue;
            long long target = (max_s - min_s) / 2;
            int best_h = -1, best_l = -1; long long best_diff = LLONG_MAX;
            int hs = std::min((int)group_items[heavy_g].size(), 8);
            int ls = std::min((int)group_items[light_g].size(), 8);
            for (int hi = 0; hi < hs; hi++) {
                int h_item = group_items[heavy_g][hi];
                for (int li = 0; li < ls; li++) {
                    int l_item = group_items[light_g][li];
                    long long wd = estimated_weights[h_item] - estimated_weights[l_item];
                    if (wd > 0) {
                        long long diff = std::abs(wd - target);
                        if (diff < best_diff) { best_diff = diff; best_h = h_item; best_l = l_item; }
                    }
                }
            }
            if (best_h == -1 || best_l == -1) continue;
            long long w1 = estimated_weights[best_h], w2 = estimated_weights[best_l];
            long long old1 = group_sums[heavy_g], old2 = group_sums[light_g];
            long long new1 = old1 - w1 + w2, new2 = old2 - w2 + w1;
            double new_sq = current_sum_sq - (double)old1*old1 - (double)old2*old2 + (double)new1*new1 + (double)new2*new2;
            double new_var = calculate_variance_from_sums(new_sq, (double)total_sum, D);
            double delta = new_var - current_var;
            if (delta < 0 || (T > 1e-15 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var; current_sum_sq = new_sq;
                group_sums[heavy_g] = new1; group_sums[light_g] = new2;
                assignment[best_h] = light_g; assignment[best_l] = heavy_g;
                int pos1 = item_pos[best_h]; int back1 = group_items[heavy_g].back();
                if (best_h != back1) { group_items[heavy_g][pos1] = back1; item_pos[back1] = pos1; }
                group_items[heavy_g].pop_back();
                int pos2 = item_pos[best_l]; int back2 = group_items[light_g].back();
                if (best_l != back2) { group_items[light_g][pos2] = back2; item_pos[back2] = pos2; }
                group_items[light_g].pop_back();
                group_items[light_g].push_back(best_h); item_pos[best_h] = group_items[light_g].size() - 1;
                group_items[heavy_g].push_back(best_l); item_pos[best_l] = group_items[heavy_g].size() - 1;
                if (new_var < best_var) { best_var = new_var; best_assignment = assignment; }
            }
        } else if (move < 8) {
            int item = item_dist(rng_engine);
            int old_g = assignment[item];
            int new_g = group_dist_r(rng_engine);
            if (new_g == old_g) continue;
            long long w = estimated_weights[item];
            long long old_a = group_sums[old_g], old_b = group_sums[new_g];
            long long new_a = old_a - w, new_b = old_b + w;
            double new_sq = current_sum_sq - (double)old_a*old_a - (double)old_b*old_b + (double)new_a*new_a + (double)new_b*new_b;
            double new_var = calculate_variance_from_sums(new_sq, (double)total_sum, D);
            double delta = new_var - current_var;
            if (delta < 0 || (T > 1e-15 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var; current_sum_sq = new_sq;
                group_sums[old_g] = new_a; group_sums[new_g] = new_b;
                assignment[item] = new_g;
                int pos = item_pos[item]; int last = group_items[old_g].back();
                if (item != last) { group_items[old_g][pos] = last; item_pos[last] = pos; }
                group_items[old_g].pop_back();
                group_items[new_g].push_back(item); item_pos[item] = group_items[new_g].size() - 1;
                if (new_var < best_var) { best_var = new_var; best_assignment = assignment; }
            }
        } else {
            int g1 = group_dist_r(rng_engine), g2 = group_dist_r(rng_engine);
            if (g1 == g2 || group_items[g1].empty() || group_items[g2].empty()) continue;
            int item1 = group_items[g1][rng_engine() % group_items[g1].size()];
            int item2 = group_items[g2][rng_engine() % group_items[g2].size()];
            long long w1 = estimated_weights[item1], w2 = estimated_weights[item2];
            long long old1 = group_sums[g1], old2 = group_sums[g2];
            long long new1 = old1 - w1 + w2, new2 = old2 - w2 + w1;
            double new_sq = current_sum_sq - (double)old1*old1 - (double)old2*old2 + (double)new1*new1 + (double)new2*new2;
            double new_var = calculate_variance_from_sums(new_sq, (double)total_sum, D);
            double delta = new_var - current_var;
            if (delta < 0 || (T > 1e-15 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = new_var; current_sum_sq = new_sq;
                group_sums[g1] = new1; group_sums[g2] = new2;
                assignment[item1] = g2; assignment[item2] = g1;
                int pos1 = item_pos[item1]; int back1 = group_items[g1].back();
                if (item1 != back1) { group_items[g1][pos1] = back1; item_pos[back1] = pos1; }
                group_items[g1].pop_back();
                int pos2 = item_pos[item2]; int back2 = group_items[g2].back();
                if (item2 != back2) { group_items[g2][pos2] = back2; item_pos[back2] = pos2; }
                group_items[g2].pop_back();
                group_items[g2].push_back(item1); item_pos[item1] = group_items[g2].size() - 1;
                group_items[g1].push_back(item2); item_pos[item2] = group_items[g1].size() - 1;
                if (new_var < best_var) { best_var = new_var; best_assignment = assignment; }
            }
        }
    }

    for (int i = 0; i < N; i++) {
        std::cout << best_assignment[i] << (i == N - 1 ? "" : " ");
    }
    std::cout << std::endl;
    return 0;
}
